"use client";

import React, { useState, useCallback } from "react";
import { Mic, Send, StopCircle, Sparkles } from "lucide-react";
import { useSettings } from "@/hooks/useSettings";
import { useAudioRecorder } from "@/hooks/useAudioRecorder";
import { transcribeAudio } from "@/lib/mistral";

interface MistralChatProps {
    onTranscription?: (text: string) => void;
}

export default function MistralChat({ onTranscription }: MistralChatProps) {
    const { settings } = useSettings();
    const [input, setInput] = useState("");
    // const [isRecording, setIsRecording] = useState(false); // Managed by hook

    const [messages, setMessages] = useState<{ role: 'user' | 'assistant'; content: string }[]>([
        { role: "assistant", content: "Hello! I'm your Mistral AI assistant. Start typing or recording to transcribe." }
    ]);

    const handleTranscriptionChunk = useCallback(async (blob: Blob) => {
        if (!settings.mistralApiKey) return;
        // Using 'mistral-large-latest' or 'voxtral-mini' if available.
        // Default to what's in settings.
        // Need to handle model naming properly (some might not support audio).
        const text = await transcribeAudio(blob, settings.mistralApiKey, settings.selectedModel || "mistral-tiny");
        if (text && onTranscription) {
            onTranscription(text);
            // Also logging to chat
            setMessages(prev => [...prev, { role: "assistant", content: `[Transcribed]: ${text}` }]);
        }
    }, [settings.mistralApiKey, settings.selectedModel, onTranscription]);

    const { isRecording, startRecording, stopRecording } = useAudioRecorder(handleTranscriptionChunk);

    const handleSend = () => {
        if (!input.trim()) return;
        setMessages([...messages, { role: "user", content: input }]);
        setInput("");
        // TODO: Call Mistral Chat API
        // Simulate response
        setTimeout(() => {
            setMessages(prev => [...prev, { role: "assistant", content: "I received your message. Integration pending." }]);
        }, 1000);
    };

    const toggleRecording = () => {
        if (isRecording) {
            stopRecording();
        } else {
            startRecording();
        }
    };

    return (
        <div className="flex flex-col h-full bg-black/20 backdrop-blur-sm">
            {/* Messages Area */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4">
                {messages.map((msg, i) => (
                    <div
                        key={i}
                        className={`flex ${msg.role === "user" ? "justify-end" : "justify-start"}`}
                    >
                        <div
                            className={`max-w-[85%] rounded-2xl px-4 py-2 text-sm ${msg.role === "user"
                                ? "bg-purple-600/80 text-white"
                                : "bg-white/10 text-gray-200"
                                }`}
                        >
                            {msg.content}
                        </div>
                    </div>
                ))}
            </div>

            {/* Input Area */}
            <div className="p-3 border-t border-white/10 bg-black/40">
                <div className="relative flex items-center gap-2">
                    <button
                        onClick={toggleRecording}
                        className={`p-2 rounded-full transition-all ${isRecording
                            ? "bg-red-500/20 text-red-400 animate-pulse border border-red-500/50"
                            : "bg-white/5 text-gray-400 hover:text-white hover:bg-white/10"
                            }`}
                        title="Start/Stop Transcription"
                    >
                        {isRecording ? <StopCircle size={20} /> : <Mic size={20} />}
                    </button>

                    <input
                        type="text"
                        value={input}
                        onChange={(e) => setInput(e.target.value)}
                        onKeyDown={(e) => e.key === "Enter" && handleSend()}
                        placeholder="Ask Mistral..."
                        className="flex-1 bg-transparent border-none focus:ring-0 text-sm text-white placeholder:text-gray-500"
                    />

                    <button
                        onClick={handleSend}
                        className="p-2 text-purple-400 hover:text-purple-300 transition-colors"
                    >
                        <Send size={18} />
                    </button>
                </div>
                {isRecording && (
                    <div className="mt-2 text-xs text-red-300 flex items-center gap-1 justify-center">
                        <span className="w-2 h-2 rounded-full bg-red-500 animate-ping" />
                        Recording... ({settings.selectedModel || "Voxtral"})
                    </div>
                )}
            </div>
        </div>
    );
}

"use client";

import React, { useRef } from "react";
import Editor, { OnMount } from "@monaco-editor/react";

interface EditorPaneProps {
    value: string;
    onChange: (value: string | undefined) => void;
    language?: string;
}

export default function EditorPane({ value, onChange, language = "markdown" }: EditorPaneProps) {
    const editorRef = useRef<any>(null);

    const handleEditorDidMount: OnMount = (editor, monaco) => {
        editorRef.current = editor;
        // Configure darker theme or custom glass feel if possible, 
        // but Monaco renders in canvas/dom elements that override transparency.
        // We can set 'vs-dark' and transparent background in options.
        monaco.editor.defineTheme('glass-dark', {
            base: 'vs-dark',
            inherit: true,
            rules: [],
            colors: {
                'editor.background': '#00000000', // Transparent
            }
        });
        monaco.editor.setTheme('glass-dark');
    };

    return (
        <div className="h-full w-full overflow-hidden rounded-xl border border-white/5 bg-black/20 backdrop-blur-sm">
            <Editor
                height="100%"
                defaultLanguage={language}
                defaultValue={value}
                value={value}
                onChange={onChange}
                theme="vs-dark" // will be overridden by onMount
                onMount={handleEditorDidMount}
                options={{
                    minimap: { enabled: false },
                    fontSize: 14,
                    fontFamily: "'Fira Code', 'Cascadia Code', Consolas, monospace",
                    wordWrap: "on",
                    padding: { top: 16 },
                    scrollBeyondLastLine: false,
                    smoothScrolling: true,
                    cursorBlinking: "smooth",
                    cursorSmoothCaretAnimation: "on",
                    formatOnPaste: true,
                    formatOnType: true,
                }}
            />
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { Folder, FileText, RefreshCw, ChevronLeft } from "lucide-react";
import { useSettings } from "@/hooks/useSettings";
import { listRepoFiles, FileItem } from "@/lib/github";

interface FileExplorerProps {
    onSelectFile: (path: string) => void;
    className?: string;
}

export default function FileExplorer({ onSelectFile, className = "" }: FileExplorerProps) {
    const { settings } = useSettings();
    const [files, setFiles] = useState<FileItem[]>([]);
    const [currentPath, setCurrentPath] = useState("");
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");

    const loadFiles = React.useCallback(async (path: string) => {
        if (!settings.githubApiKey || !settings.githubRepo) {
            setError("Configure GitHub settings first.");
            return;
        }
        setLoading(true);
        setError("");
        const [owner, repo] = settings.githubRepo.split("/");
        if (!owner || !repo) {
            setError("Invalid Repo format (owner/repo)");
            setLoading(false);
            return;
        }

        try {
            const items = await listRepoFiles(settings.githubApiKey, owner, repo, path);
            // Sort: Directores first
            items.sort((a, b) => (a.type === b.type ? a.name.localeCompare(b.name) : a.type === "dir" ? -1 : 1));
            setFiles(items);
            setCurrentPath(path);
        } catch (e) {
            setError("Failed to load files.");
        } finally {
            setLoading(false);
        }
    }, [settings.githubApiKey, settings.githubRepo]);

    useEffect(() => {
        if (settings.githubApiKey && settings.githubRepo) {
            loadFiles("");
        }
    }, [loadFiles, settings.githubApiKey, settings.githubRepo]);

    const handleNavigate = (path: string) => {
        loadFiles(path);
    };

    const handleUp = () => {
        const parts = currentPath.split("/").filter(Boolean);
        parts.pop();
        handleNavigate(parts.join("/"));
    };

    return (
        <div className={`flex flex-col h-full bg-black/20 backdrop-blur-sm ${className}`}>
            {/* Header */}
            <div className="p-2 border-b border-white/10 flex items-center justify-between text-xs">
                <div className="flex items-center gap-1 overflow-hidden">
                    {currentPath && (
                        <button onClick={handleUp} className="p-1 hover:bg-white/10 rounded">
                            <ChevronLeft size={14} />
                        </button>
                    )}
                    <span className="truncate font-mono opacity-70">{currentPath || "/"}</span>
                </div>
                <button
                    onClick={() => loadFiles(currentPath)}
                    className={`p-1 hover:bg-white/10 rounded ${loading ? "animate-spin" : ""}`}
                    title="Refresh"
                >
                    <RefreshCw size={14} />
                </button>
            </div>

            {/* Content */}
            <div className="flex-1 overflow-y-auto p-2 space-y-1">
                {error && <div className="text-red-400 text-xs p-2 text-center">{error}</div>}

                {!settings.githubApiKey && (
                    <div className="text-gray-500 text-xs p-4 text-center">
                        Go to Settings to connect GitHub.
                    </div>
                )}

                {files.map((file) => (
                    <button
                        key={file.path}
                        onClick={() => {
                            if (file.type === "dir") {
                                handleNavigate(file.path);
                            } else {
                                onSelectFile(file.path);
                            }
                        }}
                        className="w-full flex items-center gap-2 p-2 hover:bg-white/5 rounded-md text-sm text-left transition-colors group"
                    >
                        {file.type === "dir" ? (
                            <Folder size={16} className="text-blue-400 group-hover:text-blue-300" />
                        ) : (
                            <FileText size={16} className="text-gray-400 group-hover:text-white" />
                        )}
                        <span className="truncate text-gray-300 group-hover:text-white">{file.name}</span>
                    </button>
                ))}

                {!loading && files.length === 0 && !error && settings.githubApiKey && (
                    <div className="text-gray-600 text-xs text-center mt-4">No files found.</div>
                )}
            </div>
        </div>
    );
}

"use client";

import React, { useState } from "react";
import { Mosaic, MosaicNode, MosaicWindow } from "react-mosaic-component";
import "react-mosaic-component/react-mosaic-component.css";
import { clsx } from "clsx";
import { Maximize2, Minimize2, MoreHorizontal, Settings, Save } from "lucide-react";
import { useSettings } from "@/hooks/useSettings";
import { getFileContent, saveFileContent } from "@/lib/github";

import SettingsModal from "../ui/SettingsModal";
import EditorPane from "../editor/EditorPane";
import MistralChat from "../ai/MistralChat";
import FileExplorer from "../files/FileExplorer";

export type ViewId = "editor" | "preview" | "ai-chat" | "media" | "settings" | "files";

const INITIAL_LAYOUT: MosaicNode<ViewId> = {
    direction: "row",
    first: "files",
    second: {
        direction: "row",
        first: "editor",
        second: {
            direction: "column",
            first: "preview",
            second: "ai-chat",
        },
        splitPercentage: 60,
    },
    splitPercentage: 20,
};

const TITLE_MAP: Record<ViewId, string> = {
    editor: "Editor",
    preview: "Preview",
    "ai-chat": "Mistral AI",
    media: "Media Gallery",
    settings: "Settings",
    files: "Files",
};

export default function AppShell() {
    const { settings } = useSettings();
    const [layout, setLayout] = useState<MosaicNode<ViewId> | null>(INITIAL_LAYOUT);
    const [isSettingsOpen, setIsSettingsOpen] = useState(false);
    const [editorContent, setEditorContent] = useState("# Welcome to Mistral Notes\nStart typing...");
    const [currentFilePath, setCurrentFilePath] = useState<string | null>(null);
    const [isSaving, setIsSaving] = useState(false);

    const handleLoadFile = async (path: string) => {
        if (!settings.githubApiKey || !settings.githubRepo) {
            alert("GitHub API Key or Repository not set in settings.");
            return;
        }
        const [owner, repo] = settings.githubRepo.split("/");

        // Show loading state? 
        setCurrentFilePath(path);
        try {
            const content = await getFileContent(settings.githubApiKey, owner, repo, path);
            setEditorContent(content);
        } catch (error) {
            console.error("Failed to load file:", error);
            alert(`Failed to load file: ${path}. Check console for details.`);
            setEditorContent(""); // Clear editor on load failure
        }
    };

    const handleSave = async () => {
        if (!currentFilePath || !settings.githubApiKey || !settings.githubRepo) {
            alert("No file selected or GitHub settings missing. Please select a file or configure GitHub.");
            return;
        }
        setIsSaving(true);
        const [owner, repo] = settings.githubRepo.split("/");
        try {
            await saveFileContent(settings.githubApiKey, owner, repo, currentFilePath, editorContent);
            // Saved!
        } catch (e) {
            console.error("Failed to save file:", e);
            alert("Failed to save file. Check console for details.");
        } finally {
            setIsSaving(false);
        }
    };

    return (
        <div className="h-screen w-screen overflow-hidden bg-background text-foreground flex flex-col">
            {/* Height 100vh, heavy glass effect background handled in global.css on body */}
            <div className="flex-1 relative">
                <Mosaic<ViewId>
                    renderTile={(id, path) => (
                        <MosaicWindow<ViewId>
                            path={path}
                            createNode={() => "editor"}
                            title={`${TITLE_MAP[id]}${id === 'editor' && currentFilePath ? ` - ${currentFilePath}` : ''}`}
                            toolbarControls={[]} // Custom controls if needed
                            renderToolbar={(props) => (
                                <div className="flex items-center justify-between px-3 h-full w-full select-none cursor-move group">
                                    <span className="font-semibold text-sm opacity-80 flex items-center gap-2 group-hover:text-white transition-colors">
                                        {TITLE_MAP[id]} {id === 'editor' && currentFilePath && <span className="opacity-50 text-xs font-normal">({currentFilePath})</span>}
                                    </span>
                                    <div className="flex items-center gap-2">
                                        {/* Settings Trigger for Files pane (or global) */}
                                        {id === 'files' && (
                                            <button onClick={() => setIsSettingsOpen(true)} className="p-1 hover:bg-white/10 rounded-md transition-colors text-gray-400 hover:text-white">
                                                <Settings size={14} />
                                            </button>
                                        )}
                                        {id === 'editor' && (
                                            <button
                                                onClick={handleSave}
                                                className={`p-1 hover:bg-white/10 rounded-md transition-colors ${isSaving ? "text-yellow-400 animate-pulse" : "text-gray-400 hover:text-white"}`}
                                                title="Save to GitHub"
                                            >
                                                <Save size={14} />
                                            </button>
                                        )}
                                        {/* Default window controls could go here if managed manually */}
                                    </div>
                                </div>
                            )}
                        >
                            <div className="h-full w-full relative glass-panel rounded-none border-t-0 border-x-0 border-b-0 overflow-hidden">
                                {id === 'editor' ? (
                                    <EditorPane value={editorContent} onChange={(v) => setEditorContent(v || "")} />
                                ) : id === 'ai-chat' ? (
                                    <MistralChat onTranscription={(text) => setEditorContent(prev => prev + " " + text)} />
                                ) : id === 'files' ? (
                                    <FileExplorer onSelectFile={handleLoadFile} />
                                ) : (
                                    <div className="p-4 flex items-center justify-center h-full opacity-50 flex-col gap-2">
                                        {TITLE_MAP[id]} Component
                                    </div>
                                )}
                            </div>
                        </MosaicWindow>
                    )}
                    value={layout}
                    onChange={setLayout}
                    className="mosaic-blueprint-theme" // or custom
                />
            </div>
            <SettingsModal isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} />
        </div>
    );
}

"use client";

import React, { useState, useEffect } from "react";
import { X, ExternalLink, Key } from "lucide-react";
import { useSettings } from "@/hooks/useSettings";
import { fetchMistralModels } from "@/lib/mistral";

interface SettingsModalProps {
    isOpen: boolean;
    onClose: () => void;
}

export default function SettingsModal({ isOpen, onClose }: SettingsModalProps) {
    const { settings, updateSettings } = useSettings();
    const [formState, setFormState] = useState(settings);
    const [models, setModels] = useState<any[]>([]);
    const [loadingModels, setLoadingModels] = useState(false);

    // Sync internal state when settings load
    React.useEffect(() => {
        setFormState(settings);
        if (settings.mistralApiKey && isOpen) {
            fetchMistralModels(settings.mistralApiKey).then(setModels);
        }
    }, [settings, isOpen]);

    if (!isOpen) return null;

    const handleSave = () => {
        updateSettings(formState);
        onClose();
    };

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm">
            <div className="glass-panel w-full max-w-md p-6 rounded-2xl relative border border-white/10 shadow-2xl bg-[#111115]">
                <button
                    onClick={onClose}
                    className="absolute top-4 right-4 text-gray-400 hover:text-white transition-colors"
                >
                    <X size={20} />
                </button>

                <h2 className="text-xl font-bold mb-6 flex items-center gap-2">
                    <Key className="text-purple-400" size={20} />
                    Settings & Keys
                </h2>

                <div className="space-y-4">
                    {/* Mistral Section */}
                    <div className="space-y-2">
                        <label className="text-sm font-medium text-gray-300 flex justify-between">
                            Mistral API Key
                            <a
                                href="https://console.mistral.ai/api-keys/"
                                target="_blank"
                                rel="noopener noreferrer"
                                className="text-purple-400 text-xs flex items-center gap-1 hover:underline"
                            >
                                Get Key <ExternalLink size={10} />
                            </a>
                        </label>
                        <input
                            type="password"
                            value={formState.mistralApiKey}
                            onChange={(e) =>
                                setFormState({ ...formState, mistralApiKey: e.target.value })
                            }
                            className="w-full bg-black/30 border border-white/10 rounded-md px-3 py-2 text-sm text-white focus:outline-none focus:border-purple-500 transition-colors placeholder:text-gray-600"
                            placeholder="sk-..."
                        />
                    </div>

                    {/* Model Selection */}
                    <div className="space-y-2">
                        <label className="text-sm font-medium text-gray-300 flex justify-between items-center">
                            Default Model
                            <button
                                onClick={async () => {
                                    setLoadingModels(true);
                                    const mods = await fetchMistralModels(formState.mistralApiKey);
                                    setModels(mods);
                                    setLoadingModels(false);
                                }}
                                className="text-xs text-purple-400 hover:text-white transition-colors"
                                disabled={!formState.mistralApiKey || loadingModels}
                            >
                                {loadingModels ? "Loading..." : "Refresh Models"}
                            </button>
                        </label>
                        <select
                            value={formState.selectedModel}
                            onChange={(e) => setFormState({ ...formState, selectedModel: e.target.value })}
                            className="w-full bg-black/30 border border-white/10 rounded-md px-3 py-2 text-sm text-white focus:outline-none focus:border-purple-500 transition-colors cursor-pointer"
                        >
                            <option value="voxtral-mini">Voxtral Mini (Default)</option>
                            {models.map((m: any) => (
                                <option key={m.id} value={m.id}>{m.id}</option>
                            ))}
                        </select>
                    </div>

                    {/* Github Section */}
                    <div className="space-y-2">
                        <label className="text-sm font-medium text-gray-300 flex justify-between">
                            GitHub Personal Token
                            <a
                                href="https://github.com/settings/tokens"
                                target="_blank"
                                rel="noopener noreferrer"
                                className="text-purple-400 text-xs flex items-center gap-1 hover:underline"
                            >
                                Get Token <ExternalLink size={10} />
                            </a>
                        </label>
                        <input
                            type="password"
                            value={formState.githubApiKey}
                            onChange={(e) =>
                                setFormState({ ...formState, githubApiKey: e.target.value })
                            }
                            className="w-full bg-black/30 border border-white/10 rounded-md px-3 py-2 text-sm text-white focus:outline-none focus:border-purple-500 transition-colors placeholder:text-gray-600"
                            placeholder="ghp_..."
                        />
                        <p className="text-xs text-gray-500">
                            Required for syncing notes to your repository.
                        </p>
                    </div>

                    {/* Repo Section */}
                    <div className="space-y-2">
                        <label className="text-sm font-medium text-gray-300">
                            GitHub Repository (username/repo)
                        </label>
                        <input
                            type="text"
                            value={formState.githubRepo}
                            onChange={(e) =>
                                setFormState({ ...formState, githubRepo: e.target.value })
                            }
                            className="w-full bg-black/30 border border-white/10 rounded-md px-3 py-2 text-sm text-white focus:outline-none focus:border-purple-500 transition-colors placeholder:text-gray-600"
                            placeholder="e.g. justk/my-notes"
                        />
                    </div>
                </div>

                <div className="mt-8 flex justify-end gap-3">
                    <button
                        onClick={onClose}
                        className="px-4 py-2 rounded-lg text-sm font-medium text-gray-400 hover:text-white hover:bg-white/5 transition-colors"
                    >
                        Cancel
                    </button>
                    <button
                        onClick={handleSave}
                        className="px-4 py-2 rounded-lg text-sm font-medium bg-purple-600 hover:bg-purple-500 text-white shadow-lg shadow-purple-900/20 transition-all transform hover:scale-105 active:scale-95"
                    >
                        Save Connection
                    </button>
                </div>
            </div>
        </div>
    );
}

import { useState, useRef, useCallback } from "react";

export function useAudioRecorder(onChunk: (blob: Blob) => void, silenceThreshold = 0.01) {
    const [isRecording, setIsRecording] = useState(false);
    const mediaRecorder = useRef<MediaRecorder | null>(null);
    const intervalRef = useRef<NodeJS.Timeout | null>(null);

    const startRecording = useCallback(async () => {
        try {
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
            const recorder = new MediaRecorder(stream, { mimeType: 'audio/webm' }); // webm/opus usually supported
            mediaRecorder.current = recorder;

            recorder.ondataavailable = (event) => {
                if (event.data.size > 0) {
                    onChunk(event.data);
                }
            };

            recorder.start(5000); // Chunk every 5 seconds regardless of silence for now (simplest "Live" feed)
            setIsRecording(true);
        } catch (err) {
            console.error("Failed to start recording", err);
        }
    }, [onChunk]);

    const stopRecording = useCallback(() => {
        if (mediaRecorder.current) {
            mediaRecorder.current.stop();
            mediaRecorder.current.stream.getTracks().forEach(track => track.stop());
            mediaRecorder.current = null;
        }
        setIsRecording(false);
    }, []);

    return { isRecording, startRecording, stopRecording };
}

